import axios from 'axios';

class FutbolFantasyScraper {
    constructor() {
        this.baseUrl = "https://www.futbolfantasy.com";
        this.teams = [
            "alaves", "athletic", "atletico", "barcelona", "betis", "celta", "elche",
            "espanyol", "getafe", "girona", "levante", "mallorca", "osasuna",
            "rayo-vallecano", "real-madrid", "real-oviedo", "real-sociedad",
            "sevilla", "valencia", "villarreal"
        ];
        this.headers = {
            "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36"
        };
    }

    async scrapeTeamPage(teamSlug) {
        const url = `${this.baseUrl}/laliga/equipos/${teamSlug}`;
        try {
            const res = await axios.get(url, { headers: this.headers });
            const html = res.data;
            const playerProbs = {};

            // We use Regex for scraping in JS to avoid heavy DOM libraries
            // 1. Data-probabilidad attribute pattern
            const probMatches = html.matchAll(/data-probabilidad="([^"]+)"/g);
            // This usually needs to be paired with a name or img alt.
            // For simplicity and speed in mobile, we use a robust combined regex for the typical team page structure

            // Regex to find: alt="Player Name" ... data-probabilidad="80%"
            // Note: This is an approximation of the logic used in Python
            const nameProbPattern = /alt="([^"]+)"[\s\S]{0,500}?data-probabilidad="([^"]+)"/g;
            let match;
            while ((match = nameProbPattern.exec(html)) !== null) {
                let name = match[1].trim();
                let prob = match[2];
                if (prob === "Titular") prob = "100%";
                if (prob === "Suplente") prob = "0%";
                if (prob.includes("%") || prob === "100%" || prob === "0%") {
                    playerProbs[name] = prob;
                }
            }

            // Text fallback for percentages
            const textProbPattern = /([A-ZÁÉÍÓÚÑ][a-záéíóúñ]+(?:\s+[A-ZÁÉÍÓÚÑ][a-záéíóúñ]+)+)[\s\S]{0,50}?(\d+%)/g;
            while ((match = textProbPattern.exec(html)) !== null) {
                const name = match[1].trim();
                const prob = match[2];
                if (!playerProbs[name]) playerProbs[name] = prob;
            }

            return playerProbs;
        } catch (error) {
            console.error(`Failed to scrape ${teamSlug}`, error);
            return {};
        }
    }

    async getAllLineupData() {
        console.log("Scraping FF data team by team...");
        const allProbs = {};
        // Use Promise.all for faster mobile execution
        const results = await Promise.all(this.teams.map(team => this.scrapeTeamPage(team)));
        results.forEach(probs => Object.assign(allProbs, probs));
        return allProbs;
    }
}

export default FutbolFantasyScraper;
